def _sanitize_project_ini_name(project_name):
    safe = secure_filename(str(project_name or "").strip())
    return safe or "project"


def _build_print3r_defaults(selected_printer):
    printer = selected_printer if isinstance(selected_printer, dict) else {}
    bed = printer.get("bed_size") if isinstance(printer.get("bed_size"), list) else [220, 220, 250]
    speed = printer.get("speed_settings") if isinstance(printer.get("speed_settings"), dict) else {}
    hotend = printer.get("hotend_temp") if isinstance(printer.get("hotend_temp"), dict) else {}
    bed_temp = printer.get("bed_temp") if isinstance(printer.get("bed_temp"), dict) else {}
    retraction = printer.get("retraction") if isinstance(printer.get("retraction"), dict) else {}
    nozzle_size = float(printer.get("nozzle_size", 0.4))
    default_layer = round(max(0.05, min(nozzle_size * 0.8, nozzle_size * 0.5)), 3)

    return {
        "machine_name": str(printer.get("name", "Katana Printer")),
        "machine_width": float(bed[0]) if len(bed) > 0 else 220.0,
        "machine_depth": float(bed[1]) if len(bed) > 1 else 220.0,
        "machine_height": float(bed[2]) if len(bed) > 2 else 250.0,
        "nozzle_diameter": nozzle_size,
        "filament_diameter": float(printer.get("filament_diameter", 1.75)),
        "temperature": int(hotend.get("max", hotend.get("min", 200))),
        "bed_temperature": int(bed_temp.get("max", bed_temp.get("min", 60))),
        "layer_height": default_layer,
        "first_layer_height": default_layer,
        "first_layer_temperature": int(hotend.get("max", hotend.get("min", 205))),
        "first_layer_bed_temperature": int(bed_temp.get("max", bed_temp.get("min", 60))),
        "fill_density": 20,
        "infill_pattern": "grid",
        "perimeters": 2,
        "wall_thickness": 0.0,
        "top_layers": 2,
        "top_thickness": 0.0,
        "bottom_layers": 2,
        "bottom_thickness": 0.0,
        "print_speed": int(speed.get("print_speed", 50)),
        "first_layer_speed": max(10, int(speed.get("print_speed", 50) * 0.5)),
        "perimeter_speed": int(speed.get("outer_wall_speed", 40)),
        "small_perimeter_speed": int(speed.get("outer_wall_speed", 35)),
        "travel_speed": int(speed.get("travel_speed", 150)),
        "infill_speed": int(speed.get("infill_speed", 60)),
        "bridge_speed": int(speed.get("infill_speed", 60)),
        "retraction_length": float(retraction.get("distance", 2.0)),
        "retract_speed": int(retraction.get("speed", 35)),
        "skirts": 2,
        "brims": 0,
        "rafts": 0,
        "support": "none",
        "support_angle": 60,
        "support_density": 15,
        "support_interface_layers": 2,
        "support_z_distance": 0.2,
        "support_xy_distance": 0.7,
        "support_pattern": "grid",
        "support_speed": int(speed.get("infill_speed", 60)),
        "support_interface_speed": int(speed.get("infill_speed", 60)),
        "seam": "aligned",
        "cool_fan_speed": 100,
        "cool_fan_speed_max": 100,
        "cool_fan_speed_min": 35,
        "start_gcode": str(printer.get("gcode_start", "")),
        "end_gcode": str(printer.get("gcode_end", "")),
    }


def _normalize_print3r_settings(settings, defaults):
    merged = defaults.copy()
    if not isinstance(settings, dict):
        return merged

    for key, value in settings.items():
        if key not in defaults:
            continue
        if value is None:
            continue
        if isinstance(value, str):
            stripped = value.strip()
            if stripped == "":
                continue
            value = stripped
        merged[key] = value

    numeric_fields = {
        "machine_width": float,
        "machine_depth": float,
        "machine_height": float,
        "nozzle_diameter": float,
        "filament_diameter": float,
        "temperature": int,
        "bed_temperature": int,
        "layer_height": float,
        "first_layer_height": float,
        "first_layer_temperature": int,
        "first_layer_bed_temperature": int,
        "fill_density": int,
        "perimeters": int,
        "wall_thickness": float,
        "top_layers": int,
        "top_thickness": float,
        "bottom_layers": int,
        "bottom_thickness": float,
        "print_speed": int,
        "first_layer_speed": int,
        "perimeter_speed": int,
        "small_perimeter_speed": int,
        "travel_speed": int,
        "infill_speed": int,
        "bridge_speed": int,
        "retraction_length": float,
        "retract_speed": int,
        "skirts": int,
        "brims": int,
        "rafts": int,
        "support_angle": int,
        "support_density": int,
        "support_interface_layers": int,
        "support_z_distance": float,
        "support_xy_distance": float,
        "support_speed": int,
        "support_interface_speed": int,
        "cool_fan_speed": int,
        "cool_fan_speed_max": int,
        "cool_fan_speed_min": int,
    }
    for field, cast in numeric_fields.items():
        try:
            merged[field] = cast(merged[field])
        except (TypeError, ValueError):
            merged[field] = defaults[field]

    merged["support"] = str(merged.get("support", "none"))
    merged["support_pattern"] = str(merged.get("support_pattern", "grid"))
    merged["infill_pattern"] = str(merged.get("infill_pattern", "grid"))
    merged["seam"] = str(merged.get("seam", "aligned"))
    merged["start_gcode"] = str(merged.get("start_gcode", ""))
    merged["end_gcode"] = str(merged.get("end_gcode", ""))
    merged["machine_name"] = str(merged.get("machine_name", "Katana Printer"))
    return merged


def _render_print3r_ini(settings):
    lines = []
    for key in PRINT3R_PROFILE_ORDER:
        value = settings.get(key, "")
        if isinstance(value, float):
            if value.is_integer():
                value = int(value)
            else:
                value = f"{value:.3f}".rstrip("0").rstrip(".")
        text = str(value).replace("\r\n", "\n").replace("\r", "\n").replace("\n", "\\n")
        lines.append(f"{key}={text}")
    return "\n".join(lines) + "\n"


def _resolve_project_json_path_from_payload(payload):
    base_dir = os.path.dirname(os.path.abspath(__file__))
    projects_dir = os.path.join(base_dir, "projects")

    def _safe_project_stem(name):
        return "".join([c for c in str(name) if c.isalnum() or c in (' ', '.', '_', '-')]).strip()

    project_filename = str(payload.get("project_filename", "")).strip()
    if project_filename:
        if os.path.basename(project_filename) != project_filename:
            raise ValueError("Invalid project filename")
        if ".." in project_filename or not project_filename.endswith(".json"):
            raise ValueError("Invalid project filename")
        return os.path.join(projects_dir, project_filename)

    project_name = str(payload.get("project_name", "")).strip()
    if not project_name:
        raise ValueError("project_name or project_filename is required")
    safe_name = _safe_project_stem(project_name)
    if not safe_name:
        raise ValueError("Invalid project name")
    return os.path.join(projects_dir, f"{safe_name}.json")


def _resolve_profile_ini_path_from_payload(payload):
    base_dir = os.path.dirname(os.path.abspath(__file__))
    printer_settings_dir = os.path.join(base_dir, "settings", "printer")
    settings_dir = os.path.join(base_dir, "settings")

    profile_name = str(payload.get("profile_name", "")).strip()
    if profile_name:
        safe_name = secure_filename(profile_name)
        if not safe_name:
            raise ValueError("Invalid profile name")
        primary = os.path.join(printer_settings_dir, f"{safe_name}.ini")
        fallback = os.path.join(settings_dir, f"{safe_name}.ini")
        return primary if os.path.exists(primary) else fallback

    ini_filename = str(payload.get("ini_filename", "")).strip()
    if ini_filename:
        if os.path.basename(ini_filename) != ini_filename:
            raise ValueError("Invalid INI filename")
        if ".." in ini_filename or not ini_filename.endswith(".ini"):
            raise ValueError("Invalid INI filename")
        safe_file = ini_filename
        primary = os.path.join(printer_settings_dir, safe_file)
        fallback = os.path.join(settings_dir, safe_file)
        return primary if os.path.exists(primary) else fallback

    project_name = str(payload.get("project_name", "")).strip()
    if not project_name:
        raise ValueError("profile_name, ini_filename, or project_name is required")
    safe_project = secure_filename(project_name)
    if not safe_project:
        raise ValueError("Invalid project name")
    primary = os.path.join(printer_settings_dir, f"{safe_project}.ini")
    fallback = os.path.join(settings_dir, f"{safe_project}.ini")
    return primary if os.path.exists(primary) else fallback

def _compute_normal(a, b, c):
    ux, uy, uz = b[0] - a[0], b[1] - a[1], b[2] - a[2]
    vx, vy, vz = c[0] - a[0], c[1] - a[1], c[2] - a[2]
    nx = uy * vz - uz * vy
    ny = uz * vx - ux * vz
    nz = ux * vy - uy * vx
    length = math.sqrt(nx * nx + ny * ny + nz * nz) or 1.0
    return nx / length, ny / length, nz / length

def _write_ascii_stl(path, solid_name, vertices, triangles, scale):
    with open(path, "w") as f:
        f.write(f"solid {solid_name}\n")
        for i1, i2, i3 in triangles:
            a = (vertices[i1][0] * scale, vertices[i1][1] * scale, vertices[i1][2] * scale)
            b = (vertices[i2][0] * scale, vertices[i2][1] * scale, vertices[i2][2] * scale)
            c = (vertices[i3][0] * scale, vertices[i3][1] * scale, vertices[i3][2] * scale)
            nx, ny, nz = _compute_normal(a, b, c)
            f.write(f"  facet normal {nx} {ny} {nz}\n")
            f.write("    outer loop\n")
            f.write(f"      vertex {a[0]} {a[1]} {a[2]}\n")
            f.write(f"      vertex {b[0]} {b[1]} {b[2]}\n")
            f.write(f"      vertex {c[0]} {c[1]} {c[2]}\n")
            f.write("    endloop\n")
            f.write("  endfacet\n")
        f.write(f"endsolid {solid_name}\n")

def _extract_3mf_models(file_storage, upload_dir, base_name):
    file_storage.stream.seek(0)
    generated = []
    with zipfile.ZipFile(file_storage.stream) as zf:
        model_entries = [name for name in zf.namelist() if name.lower().endswith(".model")]
        if not model_entries:
            raise ValueError("No .model payload found in 3MF file")

        for model_entry in model_entries:
            root = ET.fromstring(zf.read(model_entry))
            ns_uri = root.tag[root.tag.find("{") + 1:root.tag.find("}")]
            ns = {"m": ns_uri}
            scale = UNIT_TO_MM.get(root.attrib.get("unit", "millimeter"), 1.0)

            resources = root.find("m:resources", ns)
            if resources is None:
                continue

            for obj in resources.findall("m:object", ns):
                mesh = obj.find("m:mesh", ns)
                if mesh is None:
                    continue

                vertices_tag = mesh.find("m:vertices", ns)
                triangles_tag = mesh.find("m:triangles", ns)
                if vertices_tag is None or triangles_tag is None:
                    continue

                vertices = []
                for vtx in vertices_tag.findall("m:vertex", ns):
                    vertices.append((
                        float(vtx.attrib.get("x", 0.0)),
                        float(vtx.attrib.get("y", 0.0)),
                        float(vtx.attrib.get("z", 0.0))
                    ))

                triangles = []
                for tri in triangles_tag.findall("m:triangle", ns):
                    i1 = int(tri.attrib.get("v1", 0))
                    i2 = int(tri.attrib.get("v2", 0))
                    i3 = int(tri.attrib.get("v3", 0))
                    if i1 < len(vertices) and i2 < len(vertices) and i3 < len(vertices):
                        triangles.append((i1, i2, i3))

                if not vertices or not triangles:
                    continue

                obj_id = obj.attrib.get("id", "model")
                out_name = secure_filename(f"{base_name}_{obj_id}_{uuid.uuid4().hex[:8]}.stl")
                out_path = os.path.join(upload_dir, out_name)
                _write_ascii_stl(out_path, f"{base_name}_{obj_id}", vertices, triangles, scale)
                generated.append({
                    "filename": out_name,
                    "url": f"/static/uploads/{out_name}"
                })
    return generated
