@app.route('/api/print3r/generate_profile', methods=['POST'])
def generate_print3r_profile():
    try:
        if not request.is_json:
            return jsonify({"success": False, "error": "Content-Type must be application/json"})

        payload = request.get_json() or {}
        project_name = payload.get("project_name", "")
        if not str(project_name).strip():
            return jsonify({"success": False, "error": "Project name is required"})

        config.load_config("config.json")
        selected_printer = config.config.get("selected_printer", {})
        defaults = _build_print3r_defaults(selected_printer)
        settings = _normalize_print3r_settings(payload.get("settings", {}), defaults)
        settings["machine_name"] = str(project_name).strip()

        base_dir = os.path.dirname(os.path.abspath(__file__))
        settings_dir = os.path.join(base_dir, "settings")
        printer_dir = os.path.join(settings_dir, "printer")
        os.makedirs(printer_dir, exist_ok=True)

        profile_name = _sanitize_project_ini_name(project_name)
        filename = f"{profile_name}.ini"
        profile_path = os.path.join(printer_dir, filename)
        ini_data = _render_print3r_ini(settings)

        with open(profile_path, "w") as f:
            f.write(ini_data)

        # Compatibility copy for tools/workflows expecting ./settings/<name>.ini.
        root_profile_path = os.path.join(settings_dir, filename)
        with open(root_profile_path, "w") as f:
            f.write(ini_data)

        return jsonify({
            "success": True,
            "profile_name": profile_name,
            "filename": filename,
            "path": f"./settings/printer/{filename}",
            "compat_path": f"./settings/{filename}"
        })
    except Exception as e:
        return jsonify({"success": False, "error": "Failed to generate Print3r profile"})


@app.route('/api/print3r/parse_commands', methods=['POST'])
def parse_print3r_commands():
    try:
        if not request.is_json:
            return jsonify({"success": False, "error": "Content-Type must be application/json"})

        payload = request.get_json() or {}
        project_json_path = _resolve_project_json_path_from_payload(payload)
        ini_path = _resolve_profile_ini_path_from_payload(payload)
        slicer = str(payload.get("slicer", "slic3r")).strip() or "slic3r"
        bake_models = payload.get("bake_models", True)
        if isinstance(bake_models, str):
            bake_models = bake_models.lower() not in ("0", "false", "no", "off")
        bake_models = bool(bake_models)

        if not os.path.exists(project_json_path):
            return jsonify({"success": False, "error": "Project JSON not found"})
        if not os.path.exists(ini_path):
            return jsonify({"success": False, "error": "Project INI not found"})

        parsed = build_print3r_plate_commands(
            project_ini_path=ini_path,
            project_json_path=project_json_path,
            slicer=slicer,
            bake_models=bake_models
        )
        return jsonify({"success": True, "parsed": parsed})
    except ValueError as e:
        return jsonify({"success": False, "error": str(e)})
    except Exception as e:
        return jsonify({"success": False, "error": "Failed to parse Print3r commands"})


def _inject_print3r_verbose(argv):
    if not isinstance(argv, list):
        return []
    clean = [str(x) for x in argv if str(x).strip()]
    if not clean:
        return []
    if clean[0] != "print3r":
        raise ValueError("Only print3r commands are allowed")
    if "-vv" in clean or "-v" in clean or "--verbose" in clean:
        return clean
    return [clean[0], "-vv", *clean[1:]]


@app.route('/api/print3r/stream_run', methods=['POST'])
def stream_run_print3r_command():
    try:
        if not request.is_json:
            return jsonify({"success": False, "error": "Content-Type must be application/json"}), 400

        payload = request.get_json() or {}
        argv = payload.get("argv", [])
        cmd = _inject_print3r_verbose(argv)
        if not cmd:
            return jsonify({"success": False, "error": "Invalid command"}), 400

        base_dir = os.path.dirname(os.path.abspath(__file__))
        settings_dir = os.path.join(base_dir, "settings")
        os.makedirs(settings_dir, exist_ok=True)

        def generate():
            yield f"$ {' '.join(cmd)}\n"
            try:
                proc = subprocess.Popen(
                    cmd,
                    cwd=base_dir,
                    stdout=subprocess.PIPE,
                    stderr=subprocess.STDOUT,
                    text=True,
                    bufsize=1,
                    env={**os.environ, "PRINT3R": f"settings={settings_dir}"}
                )
            except Exception as e:
                yield f"[error] failed to launch command: {e}\n"
                return

            try:
                if proc.stdout:
                    for line in proc.stdout:
                        yield line
                code = proc.wait()
                yield f"\n[katana] process exited with code {code}\n"
            finally:
                if proc.stdout:
                    proc.stdout.close()

        return Response(stream_with_context(generate()), mimetype='text/plain')
    except ValueError as e:
        return jsonify({"success": False, "error": str(e)}), 400
    except Exception as e:
        return jsonify({"success": False, "error": "Failed to run Print3r command"}), 500


